{"code":"import json

with open(locals()['var_function-call-15503541887771276820'], 'r') as f:
    citations = json.load(f)
citation_map = {c['title']: int(c['citation_count']) for c in citations}

with open(locals()['var_function-call-982611377776759492'], 'r') as f:
    paper_docs = json.load(f)

missed_acm = []
included_acm = []

for doc in paper_docs:
    text = doc.get('text', '')
    filename = doc.get('filename', '')
    title = filename.replace('.txt', '')

    if title not in citation_map:
        continue

    is_acm = False
    if 'ACM Classification Keywords' in text:
        is_acm = True
    elif 'Permission to make digital' in text and 'ACM' in text:
        is_acm = True
    elif "licensed to ACM" in text:
        is_acm = True
    elif "Copyright" in text and text.find("ACM", text.find("Copyright")) != -1 and text.find("ACM", text.find("Copyright")) - text.find("Copyright") < 50:
        is_acm = True
    elif "ACM" in text[:3000]:
        is_acm = True

    if not is_acm:
        # Check if 'ACM' appears anywhere?
        if 'ACM' in text:
            # It appeared later in the text
            missed_acm.append(title)
    else:
        included_acm.append(title)

print("__RESULT__:")
print(json.dumps({"missed_candidates": missed_acm[:10], "total_missed_candidates": len(missed_acm)}))"}

